package com.fasterxml.jackson.core.util;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "com.fasterxml.jackson.core.util.steps"
)
public class CucumberTest {
}

package com.fasterxml.jackson.core.util.steps;

import com.fasterxml.jackson.core.util.BufferRecycler;
import com.fasterxml.jackson.core.util.TextBuffer;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.junit.Assert;

import java.util.Arrays;

public class StepDefs {
    private TextBuffer textBuffer;
    private int originalSegmentSize;
    private char[] originalContent;

    @Given("a TextBuffer with a current segment that has already exceeded the maximum standard segment length \\({int}\\)")
    public void a_TextBuffer_with_a_current_segment_that_has_already_exceeded_the_maximum_standard_segment_length(int maxLen) {
        textBuffer = new TextBuffer(new BufferRecycler());

        // Create a buffer larger than maxLen
        int size = maxLen + 1000;
        char[] data = new char[size];
        Arrays.fill(data, 'A');

        // Use resetWithShared to initialize
        textBuffer.resetWithShared(data, 0, size);

        // Force unsharing to create _currentSegment
        // getCurrentSegment() calls unshare(1)
        char[] currentSegment = textBuffer.getCurrentSegment();

        originalSegmentSize = currentSegment.length;
        originalContent = Arrays.copyOf(currentSegment, originalSegmentSize);

        Assert.assertTrue("Current segment should be larger than maxLen", originalSegmentSize > maxLen);
    }

    @When("I request to expand the current segment")
    public void i_request_to_expand_the_current_segment() {
        textBuffer.expandCurrentSegment();
    }

    @Then("the new segment size should be strictly greater than the previous segment size")
    public void the_new_segment_size_should_be_strictly_greater_than_the_previous_segment_size() {
        char[] newSegment = textBuffer.getCurrentSegment();
        Assert.assertTrue("New segment size (" + newSegment.length + ") should be > original size (" + originalSegmentSize + ")", 
                          newSegment.length > originalSegmentSize);
    }

    @Then("the new segment should preserve the existing content")
    public void the_new_segment_should_preserve_the_existing_content() {
        char[] newSegment = textBuffer.getCurrentSegment();
        // Check if content is preserved (up to original length)
        for (int i = 0; i < originalSegmentSize; i++) {
            if (newSegment[i] != originalContent[i]) {
                Assert.fail("Content mismatch at index " + i);
            }
        }
    }
}
